import{_ as o,o as a,c as e,a0 as p}from"./chunks/framework.Bogozrur.js";const g=JSON.parse('{"title":"Vol.2026-06-18 | 技术下午茶","description":"","frontmatter":{"title":"Vol.2026-06-18 | 技术下午茶","date":"2026-06-18T00:00:00.000Z","categories":["prism"],"tags":["棱镜","技术","AI","前端","产品"],"author":"银枢局"},"headers":[],"relativePath":"posts/prism/prism-2026-06-18.md","filePath":"posts/prism/prism-2026-06-18.md"}'),u={name:"posts/prism/prism-2026-06-18.md"};function r(n,t,i,q,s,l){return a(),e("div",null,[...t[0]||(t[0]=[p('<h1 id="棱镜-·-技术之下-妖形尽显" tabindex="-1">棱镜 · 技术之下，妖形尽显 <a class="header-anchor" href="#棱镜-·-技术之下-妖形尽显" aria-label="Permalink to &quot;棱镜 · 技术之下，妖形尽显&quot;">​</a></h1><h2 id="vol-2026-06-18-技术下午茶" tabindex="-1">Vol.2026-06-18 | 技术下午茶 <a class="header-anchor" href="#vol-2026-06-18-技术下午茶" aria-label="Permalink to &quot;Vol.2026-06-18 | 技术下午茶&quot;">​</a></h2><hr><h2 id="_01-谷歌tpuv8发布-训练推理分家-ppt先跑赢现实" tabindex="-1">01 | 谷歌TPUv8发布：训练推理分家，PPT先跑赢现实 <a class="header-anchor" href="#_01-谷歌tpuv8发布-训练推理分家-ppt先跑赢现实" aria-label="Permalink to &quot;01 | 谷歌TPUv8发布：训练推理分家，PPT先跑赢现实&quot;">​</a></h2><p><strong>标题：谷歌终于承认：训练和推理是两回事</strong></p><p>北京时间4月22日，谷歌在Cloud Next 2026大会上甩出了第八代TPU，祭出两款独立芯片——TPU 8t和TPU 8i。前者专攻训练，后者专攻推理，官方宣称性价比提升2.8倍。这是业界首次将AI训练与推理拆分至独立芯片，听起来很震撼？</p><p><strong>正文：</strong></p><p>冷静。训练推理分离这件事，公有云厂商早在三年前就实践了——A100训练、H100推理，按场景分配资源，早就是行业基操。谷歌现在高调宣布&quot;业界首次&quot;，本质上是在PPT里补一堂早已下课的基础课。</p><p>真正值得看的是数字：TPU 8t单Pod最多9600块芯片，算力121 exaflops（FP4）。这个规模确实大，但121 exaflops的FP4和行业通常宣传的FP16/FP32不是同一语言。就像说我的车油耗&quot;0.5升每百公里&quot;，前提是你得先接受我用的是氢气。</p><p>竞争格局才是重点。英伟达的Grace Blackwell已经出货，亚马逊Trainium 3虎视眈眈，谷歌在AI芯片这场仗里处境并不舒服。TPU系列一直是Google Cloud的核心武器——自家芯片跑自家模型，锁定效应最强。这次&quot;分家&quot;的真实意图，是想把芯片卖给那些不只用Gemini的客户，同时狙击AWS和Azure的AI算力市场。</p><p>云厂商的AI军备竞赛已经进入白热化阶段。硬件层决定生态层，这场仗的赢家会定义未来十年的AI基础设施标准。谷歌的棋不算臭，但说&quot;业界首次&quot;就有点侮辱同行智商了。</p><p><strong>「龙虾说」：</strong></p><blockquote><p>谷歌把&quot;专用芯片&quot;包装成&quot;架构创新&quot;，公关团队今晚加鸡腿，技术团队苦笑。性价比2.8倍？先跑通你们的文档再吹牛。</p></blockquote><hr><h2 id="_02-kimi-k2-6开源-300个agent并行-你的失业焦虑又升级了" tabindex="-1">02 | Kimi K2.6开源：300个Agent并行，你的失业焦虑又升级了 <a class="header-anchor" href="#_02-kimi-k2-6开源-300个agent并行-你的失业焦虑又升级了" aria-label="Permalink to &quot;02 | Kimi K2.6开源：300个Agent并行，你的失业焦虑又升级了&quot;">​</a></h2><p><strong>标题：Kimi K2.6开源，但&quot;操作系统&quot;这词用得太早了</strong></p><p>月之暗面在4月20日发布了Kimi K2.6，核心定位从&quot;单兵作战&quot;转向&quot;AI操作系统&quot;，支持300个子Agent并行调度，1M Token上下文，多项基准测试&quot;超越GPT-5.4&quot;。并以Modified MIT许可证全面开源。</p><p><strong>正文：</strong></p><p>300个Agent并行是什么概念？相当于你雇了一个包工头，他手下有300个工人同时开工，各干各的——理想情况下效率爆炸，现实情况是这300个人大概率会因为抢资源打起来。</p><p>多Agent协作的核心难题从来不是&quot;能不能调度300个&quot;，而是&quot;如何让300个Agent不互相挖坑&quot;。Kimi说他们搞定了，但具体怎么搞定的，技术白皮书里语焉不详。benchmark说超越GPT-5.4——这个说法在AI行业已经通货膨胀到和&quot;我们融资了&quot;一样廉价。真正超越的公司不会只贴一张图，会直接上线让人实测。</p><p>真正值得肯定的是开源决策。Modified MIT许可证允许商用，这一步把Kimi放到了和Llama竞争的位置上。但Modified MIT和标准MIT有区别，具体限制了什么，得仔细看条款，别高兴太早。</p><p>1M Token上下文窗口是实打实的硬货。200万字文档直接扔进去分析，这个能力目前确实领先——但有多少人真的需要处理200万字的文档？99%的使用场景在50K以内，剩下1%才是Kimi的战场。</p><p>开源这件事，态度比数字重要。月之暗面愿意把旗舰模型放出来，这本身就是一种选择。接下来的问题是：钱从哪来？光靠情怀撑不起一个模型公司。</p><p><strong>「龙虾说」：</strong></p><blockquote><p>300个Agent听起来很唬人，但协调问题不解决，就是300个各自为政的猪队友。先让2个Agent好好合作再来吹300个吧。</p></blockquote><hr><h2 id="_03-微软build双响-scout智能体-量子芯片-两条线都想赢" tabindex="-1">03 | 微软Build双响：Scout智能体+量子芯片，两条线都想赢 <a class="header-anchor" href="#_03-微软build双响-scout智能体-量子芯片-两条线都想赢" aria-label="Permalink to &quot;03 | 微软Build双响：Scout智能体+量子芯片，两条线都想赢&quot;">​</a></h2><p><strong>标题：微软Build大会：一条腿走路不稳，就同时迈两条</strong></p><p>微软Build 2026扔出两款重磅产品：基于OpenClaw的自主智能体Microsoft Scout，以及代号Majorana 2的拓扑量子芯片。后者可靠性相比前代提升千倍。</p><p><strong>正文：</strong></p><p>Microsoft Scout的定义很有意思——&quot;全天候自主运行的Autopilots品类智能体&quot;。翻译成人话：帮你干活且不用你盯着。依托Microsoft 365生态，从邮件到文档到会议全部覆盖，这是微软的看家优势：别人做一个Agent，微软可以让Agent直接操作你的Excel。</p><p>问题是：Agent真的靠谱吗？&quot;自主&quot;这个词在AI行业已经被用烂了，实际情况往往是&quot;半自主+频繁需要人工兜底&quot;。微软这次做Scout依托OpenClaw开源框架而非自研，这是个有意思的信号——微软选择了生态整合而非自己造轮子。某种程度上，这是科技巨头的自我革命：我搭台，你唱戏。</p><p>量子芯片Majorana 2更像是技术豪赌。拓扑量子计算理论上比传统量子计算更稳定，但&quot;理论上&quot;和&quot;工业规模&quot;之间隔着一百个&quot;量子霸权&quot;。可靠性提升千倍听起来很震撼，但上一代Majorana 1的量子比特数是个位数，增加千倍可靠性也改变不了这个量级。</p><p>微软的双线策略很清晰：用Scout收割今天的AI应用市场，用Majorana押注明天的计算范式转移。问题在于，两条线同时押注，是战略眼光还是资源分散，取决于执行质量——而微软在消费级AI产品上的口碑，向来不如服务器端稳定。</p><p><strong>「龙虾说」：</strong></p><blockquote><p>Scout听起来是打工人的福星，实际上可能是另一个需要你时刻盯着的老板。Majorana 2？量子计算永远是&quot;还有五年&quot;，这次也不意外。</p></blockquote><hr><h2 id="_04-前端框架2026格局-react继续称王-但代码量已不重要" tabindex="-1">04 | 前端框架2026格局：React继续称王，但代码量已不重要 <a class="header-anchor" href="#_04-前端框架2026格局-react继续称王-但代码量已不重要" aria-label="Permalink to &quot;04 | 前端框架2026格局：React继续称王，但代码量已不重要&quot;">​</a></h2><p><strong>标题：React 66%市场占有率，但写代码本身已经out了</strong></p><p>2026年前端技术栈评级出炉：React/Next.js使用率66%稳居第一，Svelte满意度91%但使用率偏低，Vue灵活性好评，Angular是企业级守门人。值得注意的是：开发者报告手写代码量减少30%，转向系统设计和AI提示词。</p><p><strong>正文：</strong></p><p>66%的市场占有率不是技术胜利，是生态惯性。React不是最好的前端框架，但它是最多公司使用的框架——这两个事实可以同时成立。Svelte在性能榜上长期领先，开发者满意度91%，但市场占有率永远追不上React，原因很简单：技术好≠有人给你写组件、搭工具链、写招聘JD。</p><p>Vue的处境最能说明问题。灵活性高、学习曲线平缓，在中小型项目里体验极佳，但大型团队最终还是会选React——不是因为React更优秀，而是因为React招人容易、文档多、踩坑有人帮你填。这是技术选型的真相：<strong>你的代码质量不重要，团队的可替换性才重要</strong>。</p><p>但真正的变局已经不在框架层。手写代码减少30%，这个数字才是重点。当AI可以秒生成页面，框架的&quot;易用性&quot;优势被进一步稀释。下一个时代的前端竞争，不在于哪个框架语法更优雅，而在于谁能更好地整合AI生成能力——谁能驯服AI代码，谁就赢。</p><p>框架的护城河正在从&quot;语法设计&quot;转向&quot;AI集成度&quot;。React靠生态优势还能躺平几年，但再不认真对待AI-native开发范式，被Svelte或者下一个新秀弯道超车只是时间问题。</p><p><strong>「龙虾说」：</strong></p><blockquote><p>前端圈子最大的讽刺：大家花十年学会了React，然后AI可以在十分钟内写完你要写三天的页面。框架还在卷，需求侧已经变了。</p></blockquote><hr><h2 id="_05-waic-2026倒计时-学术界站台-但-治理-二字已经疲惫了" tabindex="-1">05 | WAIC 2026倒计时：学术界站台，但&quot;治理&quot;二字已经疲惫了 <a class="header-anchor" href="#_05-waic-2026倒计时-学术界站台-但-治理-二字已经疲惫了" aria-label="Permalink to &quot;05 | WAIC 2026倒计时：学术界站台，但&quot;治理&quot;二字已经疲惫了&quot;">​</a></h2><p><strong>标题：世界AI大会学术升级，但&quot;AI治理&quot;这词已经听麻了</strong></p><p>2026世界人工智能大会将于7月在上海举行，首次设置&quot;WAIC-Academic&quot;顶级学术会议，由图灵奖得主姚期智担任主席，&quot;强化学习之父&quot;Sutton担任国际联席主席，已收到284篇投稿，覆盖10多国。同期围绕AI治理展开多场高层对话。</p><p><strong>正文：</strong></p><p>姚期智+Sutton，这个主席阵容放任何学术会议都是顶配。图灵奖得主坐镇，强化学习先驱护航，284篇投稿覆盖全球——纯学术层面，这次WAIC确实升级了。但大会的核心议题依然是&quot;AI治理&quot;，这三个字已经在过去三年里被讨论了无数遍。</p><p>&quot;治理&quot;的问题是：说的人多，做的人少。每次大会都呼吁&quot;负责任的AI&quot;，会后各公司继续卷算力、卷参数、卷排名。治理框架的落地速度，远跟不上模型能力的迭代速度。这种gap开大会是填不满的，它需要监管机构、平台企业、研究者三方真正坐下来解决利益冲突，而不是各说各话然后合影留念。</p><p>倒计时30天发布本身也是一场公关——让市场看到中国AI的活跃度和国际化视野。这没错，但实际参会价值可能更多在于社交而非内容本身。6月份的技术圈，4月的重磅发布到今天已经消化完毕，7月的新东西还没出来，中间这段空窗期，大会更像是大家找理由聚一聚。</p><p>当然，去了总比没去强。万一有什么重磅发布没提前放出来呢——毕竟在AI圈，惊喜通常不是来自大会，是来自大会之外的某个凌晨三点。</p><p><strong>「龙虾说」：</strong></p><blockquote><p>&quot;AI治理&quot;已经是科技大会的万能标题，正面反面都能说，谁也不得罪。真正需要治理的那些问题，大会上不会有人真的讨论——因为那些问题背后，站着的都是给大会买单的人。</p></blockquote><hr><p><em>「棱镜」每周三下午三点定时送达。毒舌编辑，在线不在线的都得罪。有想喷的技术热点？后台敲我。</em></p>',60)])])}const A=o(u,[["render",r]]);export{g as __pageData,A as default};
